// 1. Mengambil data string 'text' murni dari Webhook n8n
const rawText = items[0].json.body.text;

// 2. Mengubah string tersebut menjadi objek JSON asli
const wazuhLog = JSON.parse(rawText);

// 3. MEMPERBAIKI BIDIKAN: Langsung membidik field 'hashes' murni milik Sysmon
const fullLog = wazuhLog.win.eventdata.hashes;

// 4. Rumus Regex untuk mencari string SHA256 (64 karakter hexadecimal)
const sha256Regex = /[a-fA-F0-9]{64}/;
const match = fullLog.match(sha256Regex);

// 5. Jika hash ditemukan, keluarkan hasilnya
if (match) {
  return [{ json: { file_hash: match[0] } }];
} else {
  return [{ json: { error: "Hash SHA256 tidak ditemukan dalam log" } }];
}
